import React, { useState } from "react";
import DisplayObject from "./DisplayObject";

// Array of 10 JSON book objects used in the lab activity.
const books = [
  {
    id: 1,
    title: "The Alchemist",
    author: "Paulo Coelho",
    genre: "Fiction",
    price: "$12.99"
  },
  {
    id: 2,
    title: "Atomic Habits",
    author: "James Clear",
    genre: "Self-Help",
    price: "$15.50"
  },
  {
    id: 3,
    title: "To Kill a Mockingbird",
    author: "Harper Lee",
    genre: "Classic",
    price: "$11.25"
  },
  {
    id: 4,
    title: "1984",
    author: "George Orwell",
    genre: "Dystopian",
    price: "$13.40"
  },
  {
    id: 5,
    title: "The Hobbit",
    author: "J.R.R. Tolkien",
    genre: "Fantasy",
    price: "$14.75"
  },
  {
    id: 6,
    title: "The Silent Patient",
    author: "Alex Michaelides",
    genre: "Thriller",
    price: "$16.20"
  },
  {
    id: 7,
    title: "Pride and Prejudice",
    author: "Jane Austen",
    genre: "Romance",
    price: "$10.95"
  },
  {
    id: 8,
    title: "Sapiens",
    author: "Yuval Noah Harari",
    genre: "History",
    price: "$18.00"
  },
  {
    id: 9,
    title: "The Great Gatsby",
    author: "F. Scott Fitzgerald",
    genre: "Classic",
    price: "$9.99"
  },
  {
    id: 10,
    title: "Ikigai",
    author: "Hector Garcia and Francesc Miralles",
    genre: "Philosophy",
    price: "$13.10"
  }
];

// Log the full array in the browser console as required.
console.log("Books Array:", books);

function RandomObject() {
  // The selected book is null until the user clicks the button.
  const [selectedBook, setSelectedBook] = useState(null);

  const showRandomObject = () => {
    let randomBook = books[Math.floor(Math.random() * books.length)];

    // Try to avoid showing the same object on consecutive clicks.
    if (selectedBook && books.length > 1) {
      while (randomBook.id === selectedBook.id) {
        randomBook = books[Math.floor(Math.random() * books.length)];
      }
    }

    setSelectedBook(randomBook);
  };

  return (
    <div className="container">
      <div className="card">
        <h1 className="title">Random JSON Object Viewer</h1>
        <p className="subtitle">Welcome to RandomObject Component</p>
        <button className="random-button" onClick={showRandomObject}>
          Show Random Object
        </button>

        {selectedBook && <DisplayObject objectData={selectedBook} />}
      </div>
    </div>
  );
}

export default RandomObject;
